package USTGlobal.SeleniumJava;

public class DataType {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		String name ="Selenium";
		System.out.println (name);
		
		//boolean true or false
		boolean b= true;
		System.out.println(b);
		
		//character single character 'A'
		char c='A';
		System.out.println(c);
		
		//double 64 bit decimal 20.99
		double d=99.10;
		System.out.println(d);
		
		//float 32 bit decimal 10.5f
		float f=10.5f;
		System.out.println(f);
		
		//byte 8-bit integer 10
		int i=10;
		System.out.println(i);
		
		//short 16 bit integer 1000
		short s=10000;
		System.out.println(s);
		
		//int 32 bit integer 100000
		int j=100000;
		System.out.println(j);
		
		//long 64 bit integer 100000L
		float k=1000000000;
		System.out.println(k);
		
		
	}

}
